def gen(rng, size):
    n = max(2, min(size, 5000))
    span = max(1, n // 4)
    nums = []
    for v in range(1, span + 1):
        nums.extend([v, v])
    while len(nums) < n:
        nums.append(rng.randint(1, span))
    return [nums[:n]]

