class Solution:
    def minOperations(self, nums):
        from collections import Counter
        cnt = Counter(nums)
        total = 0
        for c in cnt.values():
            best = None
            for threes in range(c // 3 + 1):
                rem = c - 3 * threes
                if rem % 2 == 0:
                    ops = threes + rem // 2
                    if best is None or ops < best:
                        best = ops
            if best is None:
                return -1
            total += best
        return total

