var minOperations = function(nums) {
    const counts = new Map();
    for (const x of nums) counts.set(x, (counts.get(x) || 0) + 1);
    let ops = 0;
    for (const c of counts.values()) {
        if (c === 1) return -1;
        ops += Math.floor((c + 2) / 3);
    }
    return ops;
};
